l-table .line-fill-address {{\r\n      width: 86mm;\r\n    }}\r\n\r\n    .ops-detail-table .line-fill-number {{\r\n      width: 62mm;\r\n    }}\r\n\r\n    .ops-detail-table .line-fill-datetime {{\r\n      width: 48mm;\r\n    }}\r\n\r\n    .ops-or {{\r\n      display: inline-block;\r\n      margin: 0 1.4mm 0 1mm;\r\n      transform: translateY(-0.12mm);\r\n      font-family: inherit;\r\n    }}\r\n\r\n    .handover-table {{\r\n      width: auto;\r\n      display: inline-table;\r\n      border-collapse: collapse;\r\n      table-layout: auto;\r\n      border: 1mm solid #111;\r\n      margin: 0 0 2mm;\r\n      font-family: inherit;\r\n    }}\r\n\r\n    .handover-table th,\r\n    .handover-table td {{\r\n      border: 0.5mm solid #111;\r\n      height: 13.9mm;\r\n      vertical-align: middle;\r\n      padding: 0.7mm 1.6mm;\r\n      font-size: 5.1mm;\r\n      font-weight: 700;\r\n    }}\r\n\r\n    .handover-table th {{\r\n      width: 33mm;\r\n      text-align: center;\r\n      background: var(--soft);\r\n    }}\r\n\r\n    .handover-table td {{\r\n      background: #fff;\r\n      text-align: left;\r\n    }}\r\n\r\n    .handover-table .stamp-cell {{\r\n      width: 14.8mm;\r\n      max-width: 14.8mm;\r\n      min-width: 14.8mm;\r\n      padding: 0;\r\n    }}\r\n\r\n    .wf-note {{\r\n      margin-top: 1.25mm;\r\n      border-top: none;\r\n      padding-top: 1.2mm;\r\n      font-size: 3.35mm;\r\n      line-height: 1.4;\r\n      font-weight: 400;\r\n      text-align: center;\r\n    }}\r\n\r\n    .sheet.page2 {{\r\n      padding: 9mm 8mm 8mm;\r\n    }}\r\n\r\n\r\n\r\n    .sheet.page-workflow .workflow {{\r\n      margin-top: 0;\r\n    }}\r\n\r\n    .page2-layout {{\r\n      height: 100%;\r\n      display: flex;\r\n      flex-direction: column;\r\n      min-height: 0;\r\n      position: relative;\r\n    }}\r\n\r\n    .page2-half {{\r\n      min-height: 0;\r\n    }}\r\n\r\n    .notice-half {{\r\n      flex: 0 0 49%;\r\n      height: 49%;\r\n      min-height: 49%;\r\n      max-height: 49%;\r\n      padding: 0.7mm 0 28mm;\r\n      position: relative;\r\n      --notice-bottom-align: calc(0.5mm + 40px);\r\n      --notice-main-table-width: 177.6mm;\r\n    }}\r\n\r\n    .page2-cut-line {{\r\n      position: absolute;\r\n      left: 0;\r\n      right: 0;\r\n      top: 50%;\r\n      transform: translateY(-50%);\r\n      border-top: 0.45mm dashed #666;\r\n      margin: 0;\r\n    }}\r\n\r\n    .apology-half {{\r\n      flex: 1 1 auto;\r\n      display: flex;\r\n      flex-direction: column;\r\n      padding: 8.5mm 2.8mm 10mm 2.8mm;\r\n      font-family: \"HG正楷書体-PRO\", \"HG正楷書体\", \"Yu Mincho\", \"MS PMincho\", serif;\r\n      font-weight: 600;\r\n    }}\r\n\r\n    .notice-title {{\r\n      margin: 0 0 3.4mm;\r\n      text-align: center;\r\n      font-size: 7.05mm;\r\n      font-weight: 800;\r\n      letter-spacing: .02em;\r\n    }}\r\n\r\n    .notice-main-table {{\r\n      width: var(--notice-main-table-width);\r\n      margin: 0 auto;\r\n      border-collapse: separate;\r\n      border-spacing: 0;\r\n      border: 3px solid #111;\r\n      table-layout: fixed;\r\n      font-weight: 700;\r\n    }}\r\n\r\n    .notice-main-table th,\r\n    .notice-main-table td {{\r\n      border: none;\r\n      vertical-align: middle;\r\n      padding: 1.1mm 1.6mm;\r\n      word-break: break-word;\r\n    }}\r\n\r\n    .notice-main-table tr + tr th,\r\n    .notice-main-table tr + tr td {{\r\n      border-top: 1.5px solid #111;\r\n    }}\r\n\r\n    .notice-main-table th + td,\r\n    .notice-main-table td + td {{\r\n      border-left: 1.5px solid #111;\r\n    }}\r\n\r\n    .notice-main-table .label {{\r\n      width: 26.7mm;\r\n      text-align: center;\r\n      font-size: 4.95mm;\r\n      line-height: 1.22;\r\n      letter-spacing: .01em;\r\n    }}\r\n\r\n    .notice-main-table .name-cell {{\r\n      width: 83mm;\r\n      text-align: center;\r\n      font-size: 5.8mm;\r\n      letter-spacing: .01em;\r\n      font-weight: 700;\r\n    }}\r\n\r\n    .notice-main-table .sama-cell {{\r\n      width: 12.5mm;\r\n      text-align: left;\r\n      font-size: 5.65mm;\r\n      padding-left: 1.2mm;\r\n      font-weight: 400;\r\n    }}\r\n\r\n    .notice-main-table .date-cell {{\r\n      width: 55.3mm;\r\n      text-align: center;\r\n      font-size: 4.95mm;\r\n      letter-spacing: .01em;\r\n      font-weight: 400;\r\n    }}\r\n\r\n    .notice-main-table .detail-row .label {{\r\n      font-size: 5mm;\r\n    }}\r\n\r\n    .notice-main-table .detail-cell {{\r\n      font-size: 5.8mm;\r\n      text-align: left;\r\n      line-height: 1.45;\r\n      font-weight: 700;\r\n      min-height: 24mm;\r\n      padding-top: 2.4mm;\r\n      padding-bottom: 2.4mm;\r\n      padding-left: 2.2mm;\r\n    }}\r\n\r\n    .notice-main-table .detail-cell.detail-cell-single {{\r\n      text-align: center;\r\n      padding-left: 0;\r\n      padding-right: 0;\r\n    }}\r\n\r\n    .notice-main-table tr.detail-row th,\r\n    .notice-main-table tr.detail-row td {{\r\n      height: 24mm;\r\n    }}\r\n\r\n    .notice-main-table .method-cell {{\r\n      font-size: 5.1mm;\r\n      text-align: center;\r\n      line-height: 1.28;\r\n      font-weight: 400;\r\n    }}\r\n\r\n    .notice-main-table tr:first-child th,\r\n    .notice-main-table tr:first-child td {{\r\n      height: 15.5mm;\r\n    }}\r\n\r\n    .notice-main-table tr:last-child th,\r\n    .notice-main-table tr:last-child td {{\r\n      height: 12mm;\r\n    }}\r\n\r\n    .notice-message {{\r\n      margin-top: 4.4mm;\r\n      margin-left: 0;\r\n      margin-right: 0;\r\n      padding-left: calc(10mm + 24px);\r\n      padding-right: 4mm;\r\n      font-size: 4.95mm;\r\n      line-height: 1.29;\r\n      font-weight: 500;\r\n      position: static;\r\n      min-height: 56.5mm;\r\n    }}\r\n\r\n    .notice-message p {{\r\n      margin: 0;\r\n    }}\r\n\r\n    .notice-message .contact {{\r\n      position: static;\r\n      margin: 0;\r\n    }}\r\n\r\n    .pharmacist-stamp {{\r\n      width: 21.7mm;\r\n      min-width: 21.7mm;\r\n      height: 26.2mm;\r\n      border: 3px solid #111;\r\n      display: flex;\r\n      flex-direction: column;\r\n      position: absolute;\r\n      right: calc((100% - var(--notice-main-table-width)) / 2);\r\n      bottom: var(--notice-bottom-align);\r\n    }}\r\n\r\n    .pharmacist-stamp .head {{\r\n      height: 6.2mm;\r\n      border-bottom: 1.5px solid #111;\r\n      display: flex;\r\n      align-items: center;\r\n      justify-content: center;\r\n      font-size: 2.75mm;\r\n      font-weight: 700;\r\n      letter-spacing: .01em;\r\n    }}\r\n\r\n    .pharmacist-stamp .body {{\r\n      flex: 1;\r\n    }}\r\n\r\n    .notice-footer {{\r\n      position: absolute;\r\n      left: 5mm;\r\n      right: 5mm;\r\n      bottom: var(--notice-bottom-align);\r\n      margin-top: 0;\r\n      padding-left: 5mm;\r\n      padding-right: 5mm;\r\n    }}\r\n\r\n    .notice-pharmacy-name {{\r\n      font-size: 7.05mm;\r\n      letter-spacing: .04em;\r\n      font-weight: 400;\r\n      line-height: 1.1;\r\n    }}\r\n\r\n    .tel-rule {{\r\n      display: none;\r\n    }}\r\n\r\n    .tel-text {{\r\n      font-size: 4.95mm;\r\n      letter-spacing: .02em;\r\n      font-weight: 400;\r\n    }}\r\n\r\n    .apology-recipient {{\r\n      margin: 0 0 5.4mm;\r\n      padding-left: 1.2mm;\r\n      transform: translateY(48px);\r\n      font-size: 7.5mm;\r\n      letter-spacing: .03em;\r\n      line-height: 1.1;\r\n      white-space: nowrap;\r\n    }}\r\n\r\n    .apology-recipient .name {{\r\n      padding: 0;\r\n    }}\r\n\r\n    .apology-recipient .sama {{\r\n      font-size: 6.7mm;\r\n    }}\r\n\r\n    .apology-message {{\r\n      flex: 1 1 auto;\r\n      display: flex;\r\n      flex-direction: column;\r\n      justify-content: center;\r\n      margin: 0 0 0 24px;\r\n      transform: translateY(24px);\r\n      padding-left: 1.4mm;\r\n      padding-right: 1.2mm;\r\n      font-size: 5.9mm;\r\n      line-height: var(--apology-message-line-height, 2.02);\r\n      letter-spacing: .01em;\r\n    }}\r\n\r\n    .apology-message p {{\r\n      margin: 0;\r\n    }}\r\n\r\n    .apology-message .detail {{\r\n      display: inline-block;\r\n      margin: 0 0.95mm 0 0;\r\n      padding: 0 1.7mm;\r\n      min-width: 59mm;\r\n      line-height: var(--apology-detail-line-height, 1.45);\r\n    }}\r\n\r\n    .apology-message .detail-tail {{\r\n      white-space: nowrap;\r\n    }}\r\n\r\n    .apology-footer {{\r\n      margin-top: 0;\r\n      display: flex;\r\n      align-items: flex-end;\r\n      justify-content: space-between;\r\n      gap: 6mm;\r\n      padding: 0 1.2mm 0.7mm;\r\n    }}\r\n\r\n    .apology-date {{\r\n      font-size: 5.05mm;\r\n      letter-spacing: .05em;\r\n      white-space: nowrap;\r\n    }}\r\n\r\n    .apology-pharmacy {{\r\n      text-align: right;\r\n      font-size: 8.1mm;\r\n      letter-spacing: .04em;\r\n      line-height: 1.15;\r\n      white-space: nowrap;\r\n    }}\r\n\r\n    @media print {{\r\n      @page {{\r\n        size: A4 portrait;\r\n        margin: 0;\r\n      }}\r\n\r\n      html, body {{\r\n        background: #fff;\r\n      }}\r\n\r\n      .preview-root {{\r\n        display: block;\r\n        padding: 0;\r\n      }}\r\n\r\n      .sheet {{\r\n        width: 210mm;\r\n        height: 297mm;\r\n        box-shadow: none;\r\n        margin: 0;\r\n        page-break-after: always;\r\n      }}\r\n\r\n      .sheet:last-child {{\r\n        page-break-after: auto;\r\n      }}\r\n    }}\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"preview-root\">\r\n    <section class=\"sheet page1\" aria-label=\"1ページ目\">\r\n      <h1 class=\"sheet-title\">不足時チェックシート</h1>\r\n\r\n      <table class=\"check-table patient-table\">\r\n        <colgroup>\r\n          <col class=\"patient-label-col\" />\r\n          <col class=\"patient-name-col\" />\r\n          <col class=\"patient-name-col\" />\r\n          <col class=\"patient-date-col\" />\r\n        </colgroup>\r\n        <tr>\r\n          <th>患者氏名</th>\r\n          <td colspan=\"2\" class=\"patient-cell\">{value}</td>\r\n          <td class=\"patient-date-cell\">{value8}</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <div class=\"drug-sections\">\r\n        {value3}\r\n      </div>\r\n\r\n      <div class=\"workflow\">\r\n        <div class=\"handover-divider\" aria-hidden=\"true\">\r\n          <span class=\"line\"></span>\r\n        </div>\r\n\r\n        <table class=\"handover-table\" aria-label=\"渡薬者記入欄\">\r\n          <tr>\r\n            <th>渡薬者</th>\r\n            <td class=\"stamp-cell\" aria-label=\"押印欄\"></td>\r\n          </tr>\r\n        </table>\r\n\r\n        <table class=\"ops-table\">\r\n          <tr class=\"ops-row-delivery\">\r\n            <th class=\"ops-head-mark\"><span class=\"head-mark-inner\"><span class=\"head-check\" aria-hidden=\"true\"></span><span class=\"label-wrap\">宅<br />配</span></span></th>\r\n            <td>\r\n              <div class=\"ops-lines\">\r\n                <table class=\"ops-detail-table ops-detail-table-delivery\" aria-label=\"宅配詳細\">\r\n                  <colgroup>\r\n                    <col class=\"col-main\" />\r\n                    <col class=\"col-sub\" />\r\n                    <col class=\"col-value\" />\r\n                  </colgroup>\r\n                  <tr>\r\n                    <th colspan=\"2\" class=\"th-address\">住\u3000所</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>支援票の住所\u3000<span class=\"box\" aria-hidden=\"true\"></span>違う住所（<span class=\"line-fill line-fill-address\"></span>）</td>\r\n                  </tr>\r\n                  <tr>\r\n                    <th rowspan=\"2\" class=\"th-phone\">電<br />話</th>\r\n                    <th class=\"th-sub\">連絡</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>到着確認の連絡OK\u3000<span class=\"box\" aria-hidden=\"true\"></span>発送時に連絡希望</td>\r\n                  </tr>\r\n                  <tr>\r\n                    <th class=\"th-sub\">番号</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>支援票の番号\u3000<span class=\"box\" aria-hidden=\"true\"></span>違う番号（<span class=\"line-fill line-fill-number\"></span>）</td>\r\n                  </tr>\r\n                </table>\r\n              </div>\r\n            </td>\r\n          </tr>\r\n          <tr class=\"ops-row-dropoff\">\r\n            <th class=\"ops-head-mark\"><span class=\"head-mark-inner\"><span class=\"head-check\" aria-hidden=\"true\"></span><span class=\"label-wrap\">お<br />届<br />け</span></span></th>\r\n            <td>\r\n              <div class=\"ops-lines\">\r\n                <table class=\"ops-detail-table\" aria-label=\"お届け詳細\">\r\n                  <tr>\r\n                    <th>住\u3000所</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>支援票の住所\u3000<span class=\"box\" aria-hidden=\"true\"></span>違う住所（<span class=\"line-fill line-fill-address\"></span>）</td>\r\n                  </tr>\r\n                  <tr>\r\n                    <th>電\u3000話</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>支援票の番号\u3000<span class=\"box\" aria-hidden=\"true\"></span>違う番号（<span class=\"line-fill line-fill-number\"></span>）</td>\r\n                  </tr>\r\n                </table>\r\n              </div>\r\n            </td>\r\n          </tr>\r\n          <tr class=\"ops-row-visit\">\r\n            <th class=\"ops-head-mark\"><span class=\"head-mark-inner\"><span class=\"head-check\" aria-hidden=\"true\"></span><span class=\"label-wrap\">来<br />局</span></span></th>\r\n            <td>\r\n              <div class=\"ops-lines\">\r\n                <table class=\"ops-detail-table\" aria-label=\"来局詳細\">\r\n                  <tr>\r\n                    <th>予定日時</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>未定\u3000<span class=\"box\" aria-hidden=\"true\"></span>（<span class=\"line-fill line-fill-datetime\"></span>）</td>\r\n                  </tr>\r\n                  <tr>\r\n                    <th>電\u3000話</th>\r\n                    <td><span class=\"box\" aria-hidden=\"true\"></span>支援票の番号\u3000<span class=\"box\" aria-hidden=\"true\"></span>違う番号（<span class=\"line-fill line-fill-number\"></span>）</td>\r\n                  </tr>\r\n                </table>\r\n              </div>\r\n            </td>\r\n          </tr>\r\n        </table>\r\n\r\n        <p class=\"wf-note\">この紙と監査支援票、薬袋、（宅配の場合）お詫びの紙、（お届けの場合）地図を印刷したものをセットにしましょう</p>\r\n      </div>\r\n    </section>\r\n\r\n    <section class=\"sheet page2\" aria-label=\"2ページ目\">\r\n      <div class=\"page2-layout\">\r\n        <div class=\"page2-half notice-half\">\r\n          <h1 class=\"notice-title\">《おくすり不足連絡票》</h1>\r\n\r\n          <table class=\"notice-main-table\">\r\n            <tr>\r\n              <th class=\"label\">ご氏名</th>\r\n              <td class=\"name-cell\">{text}</td>\r\n              <td class=\"sama-cell\">{value2}</td>\r\n              <td class=\"date-cell\">{value8}</td>\r\n            </tr>\r\n            <tr class=\"detail-row\">\r\n              <th class=\"label\">不足薬品<br />明細</th>\r\n              <td colspan=\"3\" class=\"{value5}\">{value4}</td>\r\n            </tr>\r\n            <tr>\r\n              <th class=\"label\">お渡し方法</th>\r\n              <td colspan=\"3\" class=\"method-cell\">薬局でお渡し\u3000・\u3000宅配でお送り\u3000・\u3000ご自宅にお届け</td>\r\n            </tr>\r\n          </table>\r\n\r\n          <div class=\"notice-message\">\r\n            <p>お薬が不足し、ご迷惑をおかけして申し訳ございません。</p>\r\n            <p>ご来局の際は、こちらの連絡票をご持参ください。</p>\r\n            <p>ご不明な点がございましたら、恐れ入りますが下記まで</p>\r\n            <p class=\"contact\">お問い合わせください。</p>\r\n            <div class=\"pharmacist-stamp\" aria-label=\"担当薬剤師欄\">\r\n              <div class=\"head\">担当薬剤師</div>\r\n              <div class=\"body\"></div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"notice-footer\">\r\n            <div class=\"notice-pharmacy-name\">ファーマックス由利調剤薬局</div>\r\n            <div class=\"tel-rule\"></div>\r\n            <div class=\"tel-text\">TEL: 0184-22-8090</div>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"page2-cut-line\"></div>\r\n\r\n        <div class=\"page2-half apology-half\" style=\"--apology-message-line-height: {value6}; --apology-detail-line-height: {value7};\">\r\n          <div class=\"apology-recipient\">\r\n            <span class=\"name\">{text}</span><span class=\"sama\">\u3000{value2}</span>\r\n          </div>\r\n\r\n          <div class=\"apology-message\">\r\n            <p>このたびは当薬局をご利用いただき誠にありがとうございます。</p>\r\n            <p>先日、お渡しできなかった</p>\r\n            <p><span class=\"detail\">{value4}</span><span class=\"detail-tail\">&#12434;&#12362;&#36865;&#12426;&#12356;&#12383;&#12375;&#12414;&#12377;&#12290;</span></p>\r\n            <p>ご迷惑をおかけして申し訳ございませんでした。</p>\r\n            <p>患者様のお役に立てる様、努めてまいりますので、今後共</p>\r\n            <p>よろしくお願い致します。</p>\r\n          </div>\r\n\r\n          <div class=\"apology-footer\">\r\n            <div class=\"apology-date\">令和\u3000\u3000年\u3000\u3000月\u3000\u3000日</div>\r\n            <div class=\"apology-pharmacy\">ファーマックス由利調剤薬局</div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n  </div>\r\n  <script>\r\n    (() => {{\r\n      const MAX_APOLOGY_OVERFLOW_CHARS = 6;\r\n      const MAX_DRUG_NAME_OVERFLOW_CHARS = 3;\r\n\r\n      function relocateWorkflowIfNeeded() {{\r\n        const root = document.querySelector(\".preview-root\");\r\n        const page1 = document.querySelector(\".sheet.page1\");\r\n        const page2 = document.querySelector(\".sheet.page2\");\r\n        const workflow = page1 ? page1.querySelector(\".workflow\") : null;\r\n        if (!root || !page1 || !page2 || !workflow) return;\r\n        if (workflow.closest(\".page-workflow\")) return;\r\n\r\n        const page1Rect = page1.getBoundingClientRect();\r\n        const workflowRect = workflow.getBoundingClientRect();\r\n        const fitsInPage1 = workflowRect.bottom <= (page1Rect.bottom + 0.5);\r\n        if (fitsInPage1) return;\r\n\r\n        const workflowPage = document.createElement(\"section\");\r\n        workflowPage.className = \"sheet page-workflow\";\r\n        workflowPage.setAttribute(\"aria-label\", \"Page 2\");\r\n        workflowPage.appendChild(workflow);\r\n        root.insertBefore(workflowPage, page2);\r\n\r\n        page2.setAttribute(\"aria-label\", \"Page 3\");\r\n      }}\r\n\r\n      function fitDrugNameCells() {{\n        function measureLineContentWidth(line) {{\n          if (!(line instanceof HTMLElement)) return 0;\n\n          const rectWidth = line.getBoundingClientRect().width;\n          const scrollWidth = Number.isFinite(line.scrollWidth) ? line.scrollWidth : 0;\n\n          let rangeWidth = 0;\n          if (typeof document.createRange === \"function\") {{\n            const range = document.createRange();\n            range.selectNodeContents(line);\n            rangeWidth = range.getBoundingClientRect().width;\n          }}\n\n          return Math.max(rectWidth, scrollWidth, rangeWidth);\n        }}\n\n        const cells = document.querySelectorAll(\".drug-cell\");\n        cells.forEach((cell) => {{\n          const fit = cell.querySelector(\".drug-cell-fit\");\n          if (!fit) return;\n\n          fit.style.removeProperty(\"font-size\");\n\n          const lines = Array.from(fit.querySelectorAll(\".drug-cell-fit-line\"));\n          if (!lines.length) return;\n\n          lines.forEach((line) => line.classList.remove(\"allow-wrap\"));\n\n          const available = cell.clientWidth;\n          if (!available || available <= 0) return;\n\n          const lineDecisions = lines.map((line) => {{\n            const lineWidth = measureLineContentWidth(line);\n            const overflow = lineWidth - available;\n            if (overflow <= 0) {{\n              return {{ line, lineWidth, mode: \"fit\", overflowChars: 0 }};\n            }}\n\n            const text = (line.textContent || \"\").replace(/\\s+/g, \"\");\n            const charCount = Math.max(1, [...text].length);\n            const avgCharWidth = Math.max(1, lineWidth / charCount);\n            const overflowChars = overflow / avgCharWidth;\n            const mode = overflowChars >= MAX_DRUG_NAME_OVERFLOW_CHARS ? \"wrap\" : \"shrink\";\n            return {{ line, lineWidth, mode, overflowChars }};\n          }});\n\n          const hasWrapLine = lineDecisions.some((item) => item.mode === \"wrap\");\n          if (hasWrapLine) {{\n            // If either the top or bottom line needs wrapping, enable wrapping for this cell.\n            lines.forEach((line) => line.classList.add(\"allow-wrap\"));\n            return;\n          }}\n\n          const hasShrinkLine = lineDecisions.some((item) => item.mode === \"shrink\");\n          if (!hasShrinkLine) return;\n\n          const maxLineWidth = Math.max(...lineDecisions.map((item) => item.lineWidth));\n          let scale = Math.max(0.8, available / maxLineWidth);\n          fit.style.fontSize = String(scale) + \"em\";\n\n          for (let i = 0; i < 12; i += 1) {{\n            const adjustedMax = Math.max(...lines.map((line) => measureLineContentWidth(line)));\n            if (adjustedMax <= (available + 0.5)) break;\n\n            scale -= 0.01;\n            if (scale < 0.8) {{\n              fit.style.removeProperty(\"font-size\");\n              break;\n            }}\n            fit.style.fontSize = String(scale) + \"em\";\n          }}\n        }});\n      }}\n      function fitApologyDetailLine() {{\r\n        const rows = document.querySelectorAll(\".apology-message p\");\r\n        rows.forEach((row) => {{\r\n          const detail = row.querySelector(\".detail\");\r\n          const tail = row.querySelector(\".detail-tail\");\r\n          if (!detail || !tail) return;\r\n\r\n          detail.style.removeProperty(\"font-size\");\r\n\r\n          const detailHtml = (detail.innerHTML || \"\").toLowerCase();\r\n          if (detailHtml.includes(\"<br\")) return;\r\n\r\n          const detailText = (detail.textContent || \"\").replace(/\\s+/g, \"\");\r\n          if (!detailText) return;\r\n\r\n          const available = row.clientWidth;\r\n          if (!available || available <= 0) return;\r\n\r\n          const detailStyle = getComputedStyle(detail);\r\n          const marginRight = Number.parseFloat(detailStyle.marginRight || \"0\") || 0;\r\n\r\n          let detailWidth = detail.getBoundingClientRect().width;\r\n          let tailWidth = tail.getBoundingClientRect().width;\r\n          let needed = detailWidth + marginRight + tailWidth;\r\n          let overflow = needed - available;\r\n          if (overflow <= 0) return;\r\n\r\n          const charCount = Math.max(1, [...detailText].length);\r\n          const avgCharWidth = Math.max(1, detailWidth / charCount);\r\n          const overflowChars = overflow / avgCharWidth;\r\n          if (overflowChars >= MAX_APOLOGY_OVERFLOW_CHARS) return;\r\n\r\n          let scale = Math.max(0.72, (detailWidth - overflow) / detailWidth);\r\n          detail.style.fontSize = `${{scale}}em`;\r\n\r\n          for (let i = 0; i < 12; i += 1) {{\r\n            detailWidth = detail.getBoundingClientRect().width;\r\n            tailWidth = tail.getBoundingClientRect().width;\r\n            needed = detailWidth + marginRight + tailWidth;\r\n            if (needed <= (available + 0.5)) break;\r\n\r\n            scale -= 0.01;\r\n            if (scale < 0.72) {{\r\n              detail.style.removeProperty(\"font-size\");\r\n              break;\r\n            }}\r\n            detail.style.fontSize = `${{scale}}em`;\r\n          }}\r\n        }});\r\n      }}\r\n\r\n      function countRenderedTextLines(element) {{\n        if (!element) return 0;\n        const style = getComputedStyle(element);\n        const lineHeight = Number.parseFloat(style.lineHeight || \"0\");\n        const height = element.getBoundingClientRect().height;\n        if (!Number.isFinite(lineHeight) || lineHeight <= 0 || !Number.isFinite(height) || height <= 0) {{\n          return 0;\n        }}\n        return Math.max(1, Math.round(height / lineHeight));\n      }}\n\n      function calculateApologyLineHeights(totalLineCount) {{\n        const baseTotalLines = 6;\n        const extra = Math.max(0, totalLineCount - baseTotalLines);\n        const extraWithinLegacyRange = Math.min(extra, 3);\n        const extraBeyondLegacyRange = Math.max(0, extra - 3);\n\n        let messageLineHeight = 2.02 - (extraWithinLegacyRange * 0.12) - (extraBeyondLegacyRange * 0.08);\n        let detailLineHeight = 1.45 - (extraWithinLegacyRange * 0.10) - (extraBeyondLegacyRange * 0.06);\n\n        messageLineHeight = Math.max(1.42, messageLineHeight);\n        detailLineHeight = Math.max(0.98, detailLineHeight);\n\n        return {{\n          messageLineHeight: messageLineHeight.toFixed(2),\n          detailLineHeight: detailLineHeight.toFixed(2)\n        }};\n      }}\n\n      function fitApologyLineHeightByRenderedLines() {{\n        const half = document.querySelector(\".apology-half\");\n        const message = document.querySelector(\".apology-message\");\n        if (!half || !message) return;\n\n        const rows = Array.from(message.querySelectorAll(\"p\"));\n        if (!rows.length) return;\n\n        let totalLineCount = 0;\n        rows.forEach((row) => {{\n          totalLineCount += countRenderedTextLines(row);\n        }});\n\n        if (totalLineCount <= 0) return;\n\n        const next = calculateApologyLineHeights(totalLineCount);\n        half.style.setProperty(\"--apology-message-line-height\", next.messageLineHeight);\n        half.style.setProperty(\"--apology-detail-line-height\", next.detailLineHeight);\n      }}\n\n      function applyLayoutAdjustments() {{\n        relocateWorkflowIfNeeded();\n        fitDrugNameCells();\n        fitApologyDetailLine();\n        fitApologyLineHeightByRenderedLines();\n        fitApologyDetailLine();\n        window.requestAnimationFrame(() => {{\n          fitDrugNameCells();\n          fitApologyDetailLine();\n          fitApologyLineHeightByRenderedLines();\n          fitApologyDetailLine();\n        }});\n      }}\r\n\r\n      if (document.readyState === \"loading\") {{\r\n        document.addEventListener(\"DOMContentLoaded\", applyLayoutAdjustments, {{ once: true }});\r\n      }} else {{\r\n        applyLayoutAdjustments();\r\n      }}\r\n    }})();\r\n  </script>\r\n</body>\r\n</html>";
	}

	private static string BuildDrugSectionsHtml(IReadOnlyList<DrugRenderItem> drugs)
	{
		IReadOnlyList<DrugRenderItem> readOnlyList = drugs;
		if (readOnlyList == null || readOnlyList.Count == 0)
		{
			readOnlyList = new DrugRenderItem[1]
			{
				new DrugRenderItem("不足薬品1", "", "", "", "", "", "", "", ShowShortageReasonLine: false)
			};
		}
		bool showSectionLabel = readOnlyList.Count > 1;
		StringBuilder stringBuilder = new StringBuilder();
		for (int i = 0; i < readOnlyList.Count; i++)
		{
			stringBuilder.Append(BuildSingleDrugSectionHtml(readOnlyList[i], i, showSectionLabel));
		}
		return stringBuilder.ToString();
	}

	private static string BuildSingleDrugSectionHtml(DrugRenderItem item, int index, bool showSectionLabel)
	{
		string text = E(string.IsNullOrWhiteSpace(item.Label) ? $"不足薬品{index + 1}" : item.Label.Trim());
		string value = (showSectionLabel ? ("\n  <div class=\"drug-section-title\">" + text + "</div>") : "");
		string value2 = E(string.IsNullOrWhiteSpace(item.DrugName) ? "不足薬品" : item.DrugName.Trim());
		string value3 = (string.IsNullOrWhiteSpace(item.ShortageReasonDrugName) ? "不足薬品" : item.ShortageReasonDrugName.Trim());
		string value4 = (item.ShowShortageReasonLine ? ("<br /><span class=\"drug-shortage-reason drug-cell-fit-line\">※" + E(value3) + "不足のため</span>") : "");
		string value5 = FormatShortageLine(item.ShortageLine ?? "");
		string value6 = E((item.ArrivalLine ?? "").Trim());
		string value7 = E((item.DestinationLine ?? "").Trim());
		string value8 = FormatMultiline(item.Notes ?? "");
		return $"<section class=\"drug-section\">\r\n  {value}\r\n  <table class=\"check-table\">\r\n    <colgroup>\r\n      <col class=\"label-col\" />\r\n      <col class=\"value-col\" />\r\n      <col class=\"small-label-col\" />\r\n      <col class=\"small-value-col\" />\r\n    </colgroup>\r\n    <tr class=\"drug-main-row\">\r\n      <th>不足薬品名</th>\r\n      <td class=\"drug-cell\"><span class=\"drug-cell-fit\"><span class=\"drug-cell-fit-line\">{value2}</span>{value4}</span></td>\r\n      <th>不足数</th>\r\n      <td class=\"shortage-cell\">{value5}</td>\r\n    </tr>\r\n    <tr class=\"arrival-row\">\r\n      <th>\r\n        <div class=\"arrival-label\">\r\n          <span>入荷予定</span>\r\n        </div>\r\n      </th>\r\n      <td class=\"arrival-detail-wrap\" colspan=\"3\">\r\n        <div class=\"arrival-detail-table\" aria-label=\"入荷詳細\">\r\n          <div class=\"date-cell arrival-date-cell\">{value6}</div>\r\n          <div class=\"arrival-source-head\">入荷先</div>\r\n          <div class=\"vendors arrival-vendors-cell\">{value7}</div>\r\n        </div>\r\n      </td>\r\n    </tr>\r\n    <tr>\r\n      <th>備考</th>\r\n      <td colspan=\"3\" class=\"notes-cell\">{value8}</td>\r\n    </tr>\r\n  </table>\r\n</section>";
	}

	private static List<string> BuildDetailLines(IReadOnlyList<DrugRenderItem> drugs)
	{
		if (drugs == null || drugs.Count == 0)
		{
			return new List<string>();
		}
		List<string> list = new List<string>();
		foreach (DrugRenderItem drug in drugs)
		{
			string text = (drug.DetailLine ?? "").Trim();
			if (string.IsNullOrWhiteSpace(text))
			{
				text = (drug.DrugName ?? "").Trim();
			}
			if (!string.IsNullOrWhiteSpace(text))
			{
				list.Add(text);
			}
		}
		return list;
	}

	private static string BuildDetailLinesHtml(IReadOnlyList<string> detailLines)
	{
		if (detailLines == null || detailLines.Count == 0)
		{
			return "";
		}
		bool useBullet = detailLines.Count > 1;
		StringBuilder stringBuilder = new StringBuilder();
		foreach (string detailLine in detailLines)
		{
			if (stringBuilder.Length > 0)
			{
				stringBuilder.Append("<br />");
			}
			if (useBullet)
			{
				stringBuilder.Append("・ ");
			}
			stringBuilder.Append(E(detailLine));
		}
		return stringBuilder.ToString();
	}

	private static string E(string value)
	{
		return WebUtility.HtmlEncode(value ?? "");
	}

	private static string FormatShortageLine(string value)
	{
		string text = (value ?? "").Replace("\r\n", "\n").Replace("\r", "\n").Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		string[] array = text.Split('\n');
		StringBuilder stringBuilder = new StringBuilder();
		for (int i = 0; i < array.Length; i++)
		{
			string value2 = E((array[i] ?? "").Trim());
			if (!string.IsNullOrWhiteSpace(value2))
			{
				if (stringBuilder.Length > 0)
				{
					stringBuilder.Append("<br />");
				}
				if (i == 0)
				{
					stringBuilder.Append(value2);
					continue;
				}
				StringBuilder stringBuilder2 = stringBuilder;
				StringBuilder.AppendInterpolatedStringHandler handler = new StringBuilder.AppendInterpolatedStringHandler(38, 1, stringBuilder2);
				handler.AppendLiteral("<span class=\"shortage-subline\">");
				handler.AppendFormatted(value2);
				handler.AppendLiteral("</span>");
				stringBuilder2.Append(ref handler);
			}
		}
		return stringBuilder.ToString();
	}

	private static string FormatMultiline(string value)
	{
		return E(value).Replace("\r\n", "\n").Replace("\r", "\n").Replace("\n", "<br />");
	}
}




